import{_ as a,c as r,o as t,a2 as o}from"./chunks/framework.CIiVzG-O.js";const u=JSON.parse('{"title":"Privacy Policy","description":"","frontmatter":{},"headers":[],"relativePath":"guide/privacy.md","filePath":"guide/privacy.md","lastUpdated":1781419232000}'),i={name:"guide/privacy.md"};function s(n,e,l,c,d,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h1><p>PetReminder is designed as an offline-first application. Your privacy is important to us.</p><h2 id="local-first-design" tabindex="-1">Local-first design <a class="header-anchor" href="#local-first-design" aria-label="Permalink to &quot;Local-first design&quot;">​</a></h2><ul><li>All your reminders, settings, and purchased pet data are stored locally on your Mac.</li><li>PetReminder does not upload your data to any external servers.</li><li>No account or registration is required to use the app.</li></ul><h2 id="what-we-do-not-collect" tabindex="-1">What we do not collect <a class="header-anchor" href="#what-we-do-not-collect" aria-label="Permalink to &quot;What we do not collect&quot;">​</a></h2><ul><li>We do not collect personal files, images, or browsing history.</li><li>We do not track your activity or behavior.</li><li>We do not send your reminder data or personal information to external servers.</li><li>We do not include third-party analytics or advertising SDKs.</li></ul><h2 id="what-data-is-stored-locally" tabindex="-1">What data is stored locally <a class="header-anchor" href="#what-data-is-stored-locally" aria-label="Permalink to &quot;What data is stored locally&quot;">​</a></h2><p>The following data is stored only on your device:</p><ul><li><strong>Reminders</strong>: Titles, messages, schedules, and assigned pet preferences</li><li><strong>Settings</strong>: App configuration, language preference, theme choice</li><li><strong>Purchased pets</strong>: Downloaded <code>.catpet</code> files from in-app purchases</li><li><strong>Logs</strong>: Debug logs for troubleshooting (can be deleted at any time)</li></ul><h2 id="permissions-used-by-the-app" tabindex="-1">Permissions used by the app <a class="header-anchor" href="#permissions-used-by-the-app" aria-label="Permalink to &quot;Permissions used by the app&quot;">​</a></h2><ul><li><strong>Notifications</strong>: Required to show reminder alerts and trigger pet appearance.</li><li><strong>Files and Folders</strong>: Required to save settings and downloaded pet data.</li></ul><p>You can manage these permissions in <strong>System Settings → Privacy &amp; Security</strong> at any time.</p><h2 id="in-app-purchases" tabindex="-1">In-App Purchases <a class="header-anchor" href="#in-app-purchases" aria-label="Permalink to &quot;In-App Purchases&quot;">​</a></h2><p>In-app purchases are processed by Apple via the App Store. PetReminder does not receive or store your payment information. Purchase receipts are stored locally to verify ownership.</p><h2 id="third-party-services" tabindex="-1">Third-party services <a class="header-anchor" href="#third-party-services" aria-label="Permalink to &quot;Third-party services&quot;">​</a></h2><p>PetReminder does not include any third-party analytics, advertising, or tracking services.</p><h2 id="privacy-requests" tabindex="-1">Privacy requests <a class="header-anchor" href="#privacy-requests" aria-label="Permalink to &quot;Privacy requests&quot;">​</a></h2><p>Since PetReminder stores all data locally on your device, we do not hold any personal data on our servers. If you have questions about privacy, please contact us.</p><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><p>For privacy questions, open an issue at the project repository (<a href="https://github.com/petreminder/reminder" target="_blank" rel="noreferrer">https://github.com/petreminder/reminder</a>) or contact us at <a href="mailto:reminder@w3cub.com" target="_blank" rel="noreferrer">reminder@w3cub.com</a>.</p>',20)])])}const y=a(i,[["render",s]]);export{u as __pageData,y as default};
